/** Build optimized Unsplash URLs — smaller width = faster first load. */
export function unsplash(id: string, width: number, quality = 65): string {
  return `https://images.unsplash.com/photo-${id}?auto=format&fit=crop&w=${width}&q=${quality}`;
}

/** Tiny blur placeholder for hero / LCP images. */
export const IMAGE_BLUR =
  "data:image/jpeg;base64,";
